import{_ as l,c as o,a2 as s,o as a}from"./chunks/framework.R_9q-qV_.js";const r=JSON.parse('{"title":"正则表达式教程","description":"","frontmatter":{"date":"2024-04-08T00:00:00.000Z","tags":["正则表达式"],"categories":["计算机"]},"headers":[],"relativePath":"2024/04/正则表达式教程.md","filePath":"2024/04/正则表达式教程.md","lastUpdated":1728695892000}'),t={name:"2024/04/正则表达式教程.md"};function e(d,i,n,p,c,u){return a(),o("div",null,i[0]||(i[0]=[s('<h1 id="正则表达式教程" tabindex="-1">正则表达式教程 <a class="header-anchor" href="#正则表达式教程" aria-label="Permalink to &quot;正则表达式教程&quot;">​</a></h1><p>学习正则表达式是理解和利用文本处理和搜索的重要工具之一。以下是一个简单的学习大纲，可以帮助你逐步掌握正则表达式的基础知识和进阶应用：</p><ul><li><strong>初级阶段</strong></li></ul><ol><li><p><strong>了解正则表达式的基本概念</strong></p><ul><li>什么是正则表达式？</li><li>为什么要使用正则表达式？</li><li>正则表达式的作用和应用场景</li></ul></li><li><p><strong>掌握基本语法和元字符</strong></p><ul><li>学习常见的元字符（如<code>.</code>、<code>*</code>、<code>+</code>、<code>?</code>等）的含义和用法</li><li>了解字符类<code>[]</code>和排除字符字类<code>[^]</code>的使用</li><li>理解元字符的贪婪匹配和非贪婪匹配</li></ul></li><li><p><strong>学习基本的匹配模式</strong></p><ul><li>使用<code>.</code>匹配任意字符</li><li>使用字符类<code>[]</code>匹配指定范围的字符</li><li>使用元字符<code>*</code>、<code>+</code>、<code>?</code>进行重复匹配</li><li>使用锚点<code>^</code>和<code>$</code>匹配行的开头和结尾</li></ul></li><li><p><strong>练习和实践</strong></p><ul><li>在在线工具或文本编辑器中练习编写简单的正则表达式，如匹配邮箱地址、电话号码等。</li></ul></li></ol><ul><li><strong>中级阶段</strong></li></ul><ol start="5"><li><p><strong>深入理解分组和捕获</strong></p><ul><li>学习如何使用小括号<code>()</code>进行分组(#学习如何使用小括号进行分组)。</li><li>理解捕获组的概念和用法(#理解捕获组的概念和用法)。</li><li>学习如何引用捕获组(#学习如何引用捕获组)。</li></ul></li><li><p><strong>掌握常用的预定义字符类</strong></p><ul><li>学习如何使用<code>\\d</code>、<code>\\w</code>、<code>\\s</code>等预定义字符类匹配数字、字母、空白字符等</li></ul></li><li><p><strong>了解量词的贪婪与非贪婪</strong></p><ul><li>深入理解量词<code>*</code>、<code>+</code>、<code>?</code>的贪婪匹配和非贪婪匹配</li></ul></li><li><p><strong>学习反向引用</strong></p><ul><li>掌握如何使用<code>\\1</code>、<code>\\2</code>等反向引用捕获组</li></ul></li></ol><ul><li><strong>高级阶段</strong></li></ul><ol start="9"><li><p><strong>学习零宽断言</strong></p><ul><li>了解零宽断言的概念和分类（如正向先行断言、负向先行断言等）。</li><li>学习如何在正则表达式中应用零宽断言。</li></ul></li><li><p><strong>掌握更复杂的匹配模式</strong></p><ul><li>学习如何处理重复出现的子模式，如匹配嵌套结构等。</li></ul></li><li><p><strong>了解并使用模式修饰符</strong></p><ul><li>学习如何在正则表达式中使用修饰符，如忽略大小写、多行模式等。</li></ul></li><li><p><strong>练习和实践</strong></p><ul><li>在实际项目中应用正则表达式，如日志分析、数据清洗等场景。</li></ul></li></ol><ul><li><strong>进阶阶段</strong></li></ul><ol start="13"><li><p><strong>学习优化和性能调优</strong></p><ul><li>了解正则表达式的性能影响因素。</li><li>学习如何优化复杂正则表达式以提高性能。</li></ul></li><li><p><strong>了解其他编程语言中的正则表达式支持</strong></p><ul><li>探索其他编程语言（如Python、JavaScript、Java等）中正则表达式的语法和特性。</li></ul></li><li><p><strong>实践项目</strong></p><ul><li>参与实际项目并利用正则表达式解决实际问题，如网站爬虫、文本分析等。</li></ul></li><li><p><strong>持续学习与实践</strong></p><ul><li>跟踪正则表达式技术的最新发展和应用，不断扩展和提升自己的技能。</li></ul></li></ol><p>以上是一个大致的学习路线，你可以根据自己的学习进度和需求来安排学习计划，并结合实际项目进行练习和实践，以更好地掌握正则表达式的应用。</p><h2 id="初级阶段" tabindex="-1">初级阶段 <a class="header-anchor" href="#初级阶段" aria-label="Permalink to &quot;初级阶段&quot;">​</a></h2><h2 id="了解正则表达式的基本概念" tabindex="-1">了解正则表达式的基本概念 <a class="header-anchor" href="#了解正则表达式的基本概念" aria-label="Permalink to &quot;了解正则表达式的基本概念&quot;">​</a></h2><h3 id="什么是正则表达式" tabindex="-1">什么是正则表达式？ <a class="header-anchor" href="#什么是正则表达式" aria-label="Permalink to &quot;什么是正则表达式？&quot;">​</a></h3><p>正则表达式（Regular Expression，简称 Regex 或 RegExp）是一种用于描述字符模式的强大工具。它是由普通字符（例如字母、数字、空格等）和特殊字符（称为元字符）组成的字符串，用来匹配和搜索文本中的特定模式或字符序列。</p><p>正则表达式在文本处理、搜索和替换等领域有着广泛的应用，它可以用来实现各种文本处理任务，包括验证输入的格式、提取特定的信息、过滤文本等。通过灵活地组合普通字符和元字符，可以构建出复杂的匹配规则，使得正则表达式成为处理文本的强大工具。</p><p>举例来说，一个简单的正则表达式 <code>\\d{3}-\\d{3}-\\d{4}</code> 可以用来匹配美国的电话号码格式，其中 <code>\\d</code> 表示匹配任意数字，<code>{3}</code> 表示匹配前面的模式恰好三次，<code>-</code> 表示匹配破折号。因此，这个正则表达式可以匹配形如 &quot;123-456-7890&quot; 的电话号码。</p><p>总之，正则表达式是一种强大而灵活的工具，可以帮助程序员和数据处理人员轻松地处理和操纵文本数据。</p><h3 id="为什么要使用正则表达式" tabindex="-1">为什么要使用正则表达式？ <a class="header-anchor" href="#为什么要使用正则表达式" aria-label="Permalink to &quot;为什么要使用正则表达式？&quot;">​</a></h3><p>使用正则表达式有以下几个主要原因：</p><ol><li><p><strong>灵活性和强大性：</strong> 正则表达式提供了一种灵活、强大且高效的文本匹配和处理机制。通过正则表达式，可以描述和匹配各种复杂的文本模式，从而实现各种文本处理任务。</p></li><li><p><strong>文本搜索和替换：</strong> 正则表达式可以用于在文本中搜索指定的模式，并对匹配的文本进行替换、删除、提取等操作。这在处理大量文本数据时非常有用，可以提高搜索和替换的效率。</p></li><li><p><strong>格式验证和数据提取：</strong> 正则表达式可以用于验证输入的格式是否符合指定的要求，例如邮箱地址、电话号码、身份证号码等。同时，也可以从文本中提取出符合特定模式的信息，如提取网页中的链接、提取日志中的关键信息等。</p></li><li><p><strong>跨平台和多语言支持：</strong> 正则表达式是一种通用的文本处理工具，几乎所有主流的编程语言和操作系统都提供了对正则表达式的支持。因此，无论你使用哪种编程语言或操作系统，都可以方便地使用正则表达式来处理文本数据。</p></li><li><p><strong>简洁和高效：</strong> 正则表达式通常比手动编写复杂的文本处理代码更加简洁和高效。一行或几行正则表达式就可以实现复杂的文本匹配和处理，大大提高了开发效率和代码可读性。</p></li></ol><p>综上所述，正则表达式是一种强大而灵活的文本处理工具，可以帮助程序员和数据处理人员轻松地处理各种文本数据，提高工作效率和代码质量。</p><h3 id="正则表达式的作用和应用场景" tabindex="-1">正则表达式的作用和应用场景 <a class="header-anchor" href="#正则表达式的作用和应用场景" aria-label="Permalink to &quot;正则表达式的作用和应用场景&quot;">​</a></h3><p>正则表达式在各种领域都有广泛的应用，其主要作用和应用场景包括但不限于以下几个方面：</p><ol><li><p><strong>文本搜索和匹配：</strong> 正则表达式可以用于在文本中搜索指定的模式或匹配特定的字符序列。例如，可以使用正则表达式来查找包含特定关键词的文本、匹配邮箱地址、匹配电话号码等。</p></li><li><p><strong>数据提取和抽取：</strong> 正则表达式可以从文本中提取出符合特定模式的信息。例如，可以使用正则表达式从网页源代码中提取链接、从日志文件中提取关键信息等。</p></li><li><p><strong>格式验证和数据清洗：</strong> 正则表达式可以用于验证输入的格式是否符合指定的要求，并对数据进行清洗和预处理。例如，可以使用正则表达式验证用户输入的邮箱地址、电话号码、身份证号码等是否合法，并对其进行格式化或修复。</p></li><li><p><strong>文本替换和修改：</strong> 正则表达式可以对文本进行替换、修改或删除操作。例如，可以使用正则表达式来将文本中的特定字符串替换为其他字符串、删除文本中的空白字符、修复文本中的格式错误等。</p></li><li><p><strong>日志分析和数据挖掘：</strong> 正则表达式在日志分析和数据挖掘领域也有广泛的应用。例如，可以使用正则表达式从服务器日志中提取访问信息、分析用户行为模式等。</p></li><li><p><strong>编程语言中的模式匹配：</strong> 许多编程语言（如Python、JavaScript、Java等）都提供了对正则表达式的支持，可以在编程中使用正则表达式来实现模式匹配、字符串搜索和处理等功能。</p></li></ol><p>总的来说，正则表达式是一种强大而灵活的文本处理工具，在各种文本处理、搜索和匹配场景中都有着重要的应用价值。通过合理使用正则表达式，可以提高文本处理的效率和精度，从而更好地满足实际需求。</p><h2 id="掌握基本语法和元字符" tabindex="-1">掌握基本语法和元字符 <a class="header-anchor" href="#掌握基本语法和元字符" aria-label="Permalink to &quot;掌握基本语法和元字符&quot;">​</a></h2><h3 id="学习常见的元字符-如-、-、-、-等-的含义和用法" tabindex="-1">学习常见的元字符（如<code>.</code>、<code>*</code>、<code>+</code>、<code>?</code>等）的含义和用法 <a class="header-anchor" href="#学习常见的元字符-如-、-、-、-等-的含义和用法" aria-label="Permalink to &quot;学习常见的元字符（如`.`、`*`、`+`、`?`等）的含义和用法&quot;">​</a></h3><p>元字符是正则表达式中具有特殊含义的字符，它们用于描述模式的结构和特征。以下是一些常见的元字符及其含义和用法：</p><ol><li><p><code>.</code>（点号）：匹配任意单个字符，除了换行符 <code>\\n</code> 外的任何字符。例如，正则表达式 <code>a.c</code> 可以匹配 &quot;abc&quot;、&quot;a1c&quot;、&quot;a@c&quot; 等。</p></li><li><p><code>*</code>（星号）：匹配前面的字符零次或多次。例如，正则表达式 <code>ab*</code> 可以匹配 &quot;a&quot;、&quot;ab&quot;、&quot;abb&quot;、&quot;abbb&quot; 等。</p></li><li><p><code>+</code>（加号）：匹配前面的字符一次或多次。例如，正则表达式 <code>ab+</code> 可以匹配 &quot;ab&quot;、&quot;abb&quot;、&quot;abbb&quot; 等，但不能匹配 &quot;a&quot;。</p></li><li><p><code>?</code>（问号）：匹配前面的字符零次或一次，表示可选。例如，正则表达式 <code>ab?</code> 可以匹配 &quot;a&quot;、&quot;ab&quot;，但不能匹配 &quot;abb&quot;。</p></li><li><p><code>^</code>（脱字符）：匹配输入字符串的开始位置。例如，正则表达式 <code>^abc</code> 可以匹配以 &quot;abc&quot; 开头的字符串。</p></li><li><p><code>$</code>（美元符号）：匹配输入字符串的结束位置。例如，正则表达式 <code>abc$</code> 可以匹配以 &quot;abc&quot; 结尾的字符串。</p></li><li><p><code>[]</code>（字符类）：匹配指定范围内的任意一个字符。例如，正则表达式 <code>[abc]</code> 可以匹配 &quot;a&quot;、&quot;b&quot;、&quot;c&quot; 中的任意一个字符。</p></li><li><p><code>[^]</code>（排除字符类）：匹配除了指定范围内的任意一个字符以外的字符。例如，正则表达式 <code>[^abc]</code> 可以匹配除了 &quot;a&quot;、&quot;b&quot;、&quot;c&quot; 以外的任意一个字符。</p></li><li><p><code>()</code>（分组）：将多个字符组合成一个单元，可以对其进行量词操作或引用。例如，正则表达式 <code>(ab)+</code> 可以匹配 &quot;ab&quot;、&quot;abab&quot;、&quot;ababab&quot; 等。</p></li><li><p><code>\\</code>（反斜杠）：用于转义特殊字符，使其失去特殊含义。例如，正则表达式 <code>\\.com</code> 可以匹配 &quot;.com&quot;，而不是匹配任意字符后跟着 &quot;com&quot;。</p></li></ol><p>以上是一些常见的元字符及其含义和用法，掌握它们能够帮助你构建更加灵活和强大的正则表达式，用于实现各种文本匹配和处理任务。</p><h2 id="了解字符类-和排除字符字类-的使用" tabindex="-1">了解字符类<code>[]</code>和排除字符字类<code>[^]</code>的使用 <a class="header-anchor" href="#了解字符类-和排除字符字类-的使用" aria-label="Permalink to &quot;了解字符类`[]`和排除字符字类`[^]`的使用&quot;">​</a></h2><p>字符类 <code>[]</code> 和排除字符类 <code>[^]</code> 是正则表达式中用于匹配指定范围内字符的特殊构造。</p><ol><li>字符类 <code>[]</code>： <ul><li>字符类用于匹配方括号内的任意一个字符。</li><li>可以指定单个字符，也可以指定字符范围。</li><li>如果在字符类中使用连字符 <code>-</code>，它会表示一个字符范围。</li><li>字符类中的元字符失去特殊含义，只匹配自身字符。</li></ul></li></ol><p><strong>示例</strong>：</p><ul><li><code>[abc]</code>：匹配 &quot;a&quot;、&quot;b&quot;、&quot;c&quot; 中的任意一个字符。</li><li><code>[a-z]</code>：匹配从 &quot;a&quot; 到 &quot;z&quot; 之间的任意一个小写字母。</li></ul><ol start="2"><li>排除字符类 <code>[^]</code>： <ul><li>排除字符类用于匹配除了方括号内指定的字符之外的任意一个字符。</li><li>在字符类的开头使用插入符 <code>^</code> 表示排除字符类。</li><li>排除字符类中的元字符失去特殊含义，只匹配自身字符。</li></ul></li></ol><p><strong>示例</strong>：</p><ul><li><code>[^abc]</code>：匹配除了 &quot;a&quot;、&quot;b&quot;、&quot;c&quot; 之外的任意一个字符。</li><li><code>[^a-z]</code>：匹配除了小写字母之外的任意一个字符。</li></ul><p><strong>使用示例</strong>：</p><ul><li><code>[aeiou]</code>：匹配任意一个元音字母。</li><li><code>[0-9]</code>：匹配任意一个数字字符。</li><li><code>[^0-9]</code>：匹配除了数字字符之外的任意一个字符。</li><li><code>[A-Za-z]</code>：匹配任意一个大小写字母。</li></ul><p>总之，字符类 <code>[]</code> 和排除字符类 <code>[^]</code> 是正则表达式中用于匹配指定范围内字符的重要工具，它们可以帮助你更精确地匹配目标字符，从而实现各种文本处理任务。</p><h3 id="理解元字符的贪婪匹配和非贪婪匹配" tabindex="-1">理解元字符的贪婪匹配和非贪婪匹配 <a class="header-anchor" href="#理解元字符的贪婪匹配和非贪婪匹配" aria-label="Permalink to &quot;理解元字符的贪婪匹配和非贪婪匹配&quot;">​</a></h3><p>在正则表达式中，量词元字符（如 <code>*</code>、<code>+</code>、<code>?</code>、<code>{}</code>）通常具有贪婪匹配和非贪婪匹配两种匹配模式。</p><ol><li><strong>贪婪匹配</strong>： <ul><li>贪婪匹配是默认的匹配模式。</li><li>贪婪匹配尽可能多地匹配文本，直到无法继续匹配为止。</li><li>在量词元字符后加上 <code>?</code> 可以将其转换为非贪婪匹配模式。</li></ul></li></ol><p><strong>示例</strong>：</p><ul><li>对于正则表达式 <code>a+</code>，在文本 &quot;aaaa&quot; 中进行匹配时，贪婪匹配会尽可能匹配更多的 &quot;a&quot;，结果会匹配整个字符串 &quot;aaaa&quot;。</li><li>对于正则表达式 <code>a+?</code>，在相同的文本 &quot;aaaa&quot; 中进行匹配时，非贪婪匹配只会匹配尽可能少的 &quot;a&quot;，结果会匹配一个 &quot;a&quot;。</li></ul><ol start="2"><li><strong>非贪婪匹配（懒惰匹配）</strong>： <ul><li>非贪婪匹配尽可能少地匹配文本，以满足匹配条件为止。</li><li>在量词元字符后加上 <code>?</code> 就可以将其转换为非贪婪匹配模式。</li><li>非贪婪匹配也被称为懒惰匹配或最小匹配。</li></ul></li></ol><p><strong>示例</strong>：</p><ul><li>对于正则表达式 <code>a*</code>，在文本 &quot;aaaa&quot; 中进行匹配时，贪婪匹配会匹配整个字符串 &quot;aaaa&quot;，而非贪婪匹配会匹配空字符串，因为它尽可能少地匹配 &quot;a&quot;。</li><li>对于正则表达式 <code>a*?</code>，在相同的文本 &quot;aaaa&quot; 中进行匹配时，非贪婪匹配会匹配尽可能少的 &quot;a&quot;，结果会匹配空字符串。</li></ul><p>总之，贪婪匹配和非贪婪匹配是正则表达式中量词元字符的两种匹配模式，可以根据实际需求选择合适的模式来匹配目标文本。</p><h2 id="学习基本的匹配模式" tabindex="-1">学习基本的匹配模式 <a class="header-anchor" href="#学习基本的匹配模式" aria-label="Permalink to &quot;学习基本的匹配模式&quot;">​</a></h2><h3 id="使用-匹配任意字符" tabindex="-1">使用 <code>.</code> 匹配任意字符 <a class="header-anchor" href="#使用-匹配任意字符" aria-label="Permalink to &quot;使用 `.` 匹配任意字符&quot;">​</a></h3><p>使用<code>.</code>可以匹配任意单个字符，除了换行符 <code>\\n</code> 之外的任何字符。下面是一些示例：</p><ol><li><p>正则表达式：<code>.</code></p><ul><li>匹配：任意单个字符，除了换行符。</li><li>示例：<code>a.</code> 可以匹配 &quot;ab&quot;、&quot;ac&quot;，但不能匹配 &quot;a\\n&quot;。</li></ul></li><li><p>正则表达式：<code>a.b</code></p><ul><li>匹配：一个 &quot;a&quot; 后面跟着任意单个字符，然后再跟着一个 &quot;b&quot;。</li><li>示例：<code>a.b</code> 可以匹配 &quot;axb&quot;、&quot;a1b&quot;，但不能匹配 &quot;a\\nb&quot;。</li></ul></li><li><p>正则表达式：<code>.*</code></p><ul><li>匹配：任意数量（包括零个）的任意字符。</li><li>示例：<code>.*</code> 可以匹配任何字符串，包括空字符串。</li></ul></li><li><p>正则表达式：<code>a.*b</code></p><ul><li>匹配：以 &quot;a&quot; 开头，以 &quot;b&quot; 结尾，中间包含任意数量的任意字符的字符串。</li><li>示例：<code>a.*b</code> 可以匹配 &quot;axxxxxb&quot;、&quot;a1b&quot;、&quot;ab&quot;，但不能匹配 &quot;a\\nb&quot;。</li></ul></li></ol><p>总之，<code>.</code> 是一个匹配任意单个字符的元字符，除了换行符 <code>\\n</code> 之外的任何字符。</p><h3 id="使用字符类-匹配指定范围的字符" tabindex="-1">使用字符类<code>[]</code>匹配指定范围的字符 <a class="header-anchor" href="#使用字符类-匹配指定范围的字符" aria-label="Permalink to &quot;使用字符类`[]`匹配指定范围的字符&quot;">​</a></h3><p>字符类 <code>[]</code> 可以用来匹配指定范围内的任意一个字符。下面是一些示例：</p><ol><li><p>正则表达式：<code>[abc]</code></p><ul><li>匹配：任意一个字符，可以是 &quot;a&quot;、&quot;b&quot; 或 &quot;c&quot; 中的任意一个。</li><li>示例：<code>[abc]</code> 可以匹配 &quot;a&quot;、&quot;b&quot;、&quot;c&quot;。</li></ul></li><li><p>正则表达式：<code>[a-z]</code></p><ul><li>匹配：任意一个小写字母。</li><li>示例：<code>[a-z]</code> 可以匹配 &quot;a&quot;、&quot;b&quot;、&quot;c&quot;、...、&quot;z&quot;。</li></ul></li><li><p>正则表达式：<code>[A-Z]</code></p><ul><li>匹配：任意一个大写字母。</li><li>示例：<code>[A-Z]</code> 可以匹配 &quot;A&quot;、&quot;B&quot;、&quot;C&quot;、...、&quot;Z&quot;。</li></ul></li><li><p>正则表达式：<code>[0-9]</code></p><ul><li>匹配：任意一个数字字符。</li><li>示例：<code>[0-9]</code> 可以匹配 &quot;0&quot;、&quot;1&quot;、&quot;2&quot;、...、&quot;9&quot;。</li></ul></li><li><p>正则表达式：<code>[a-zA-Z]</code></p><ul><li>匹配：任意一个字母，可以是小写字母或大写字母。</li><li>示例：<code>[a-zA-Z]</code> 可以匹配 &quot;a&quot;、&quot;b&quot;、...、&quot;z&quot; 和 &quot;A&quot;、&quot;B&quot;、...、&quot;Z&quot;。</li></ul></li><li><p>正则表达式：<code>[0-9a-fA-F]</code></p><ul><li>匹配：任意一个十六进制字符，可以是数字 0-9 或小写字母 a-f 或大写字母 A-F。</li><li>示例：<code>[0-9a-fA-F]</code> 可以匹配 &quot;0&quot;、&quot;1&quot;、...、&quot;9&quot;、&quot;a&quot;、&quot;b&quot;、...、&quot;f&quot;、&quot;A&quot;、&quot;B&quot;、...、&quot;F&quot;。</li></ul></li></ol><p>总之，字符类 <code>[]</code> 可以用于匹配指定范围内的任意一个字符，你可以根据需要灵活地使用它来匹配目标字符。</p><h3 id="使用元字符-、-、-进行重复匹配" tabindex="-1">使用元字符<code>*</code>、<code>+</code>、<code>?</code>进行重复匹配 <a class="header-anchor" href="#使用元字符-、-、-进行重复匹配" aria-label="Permalink to &quot;使用元字符`*`、`+`、`?`进行重复匹配&quot;">​</a></h3><p>元字符 <code>*</code>、<code>+</code> 和 <code>?</code> 都是用于表示重复匹配的量词，它们可以指定前面的字符或子表达式的重复次数，具体如下：</p><ol><li><p><code>*</code>（星号）：匹配前面的字符或子表达式零次或多次。</p><ul><li>示例： <ul><li>正则表达式 <code>ab*</code> 匹配一个 &quot;a&quot; 后面跟着零个或多个 &quot;b&quot;，因此可以匹配 &quot;a&quot;、&quot;ab&quot;、&quot;abb&quot;、&quot;abbb&quot; 等。</li></ul></li></ul></li><li><p><code>+</code>（加号）：匹配前面的字符或子表达式一次或多次。</p><ul><li>示例： <ul><li>正则表达式 <code>ab+</code> 匹配一个 &quot;a&quot; 后面跟着至少一个 &quot;b&quot;，因此可以匹配 &quot;ab&quot;、&quot;abb&quot;、&quot;abbb&quot; 等，但不能匹配 &quot;a&quot;。</li></ul></li></ul></li><li><p><code>?</code>（问号）：匹配前面的字符或子表达式零次或一次，表示可选。</p><ul><li>示例： <ul><li>正则表达式 <code>ab?</code> 匹配一个 &quot;a&quot; 后面跟着零个或一个 &quot;b&quot;，因此可以匹配 &quot;a&quot;、&quot;ab&quot;，但不能匹配 &quot;abb&quot;。</li></ul></li></ul></li></ol><p>这些量词元字符可以用于构建复杂的匹配规则，你可以根据实际需求选择合适的量词来匹配目标字符串。</p><h3 id="使用锚点-和-匹配行的开头和结尾" tabindex="-1">使用锚点<code>^</code>和<code>$</code>匹配行的开头和结尾 <a class="header-anchor" href="#使用锚点-和-匹配行的开头和结尾" aria-label="Permalink to &quot;使用锚点`^`和`$`匹配行的开头和结尾&quot;">​</a></h3><p>锚点 <code>^</code> 和 <code>$</code> 分别用于匹配行的开头和结尾。</p><ul><li><code>^</code>（脱字符）：匹配输入字符串的开始位置。</li><li><code>$</code>（美元符号）：匹配输入字符串的结束位置。</li></ul><p>这些锚点可以用于限制匹配的位置，确保匹配发生在输入字符串的特定位置。以下是一些示例：</p><ol><li><p>正则表达式 <code>^Hello</code>：</p><ul><li>匹配：以 &quot;Hello&quot; 开头的字符串。</li><li>示例：<code>^Hello</code> 可以匹配 &quot;Hello, world!&quot; 中的 &quot;Hello&quot;，但不能匹配 &quot;Hi, Hello&quot; 中的 &quot;Hello&quot;。</li></ul></li><li><p>正则表达式 <code>world!$</code>：</p><ul><li>匹配：以 &quot;world!&quot; 结尾的字符串。</li><li>示例：<code>world!$</code> 可以匹配 &quot;Hello, world!&quot; 中的 &quot;world!&quot;，但不能匹配 &quot;world! Hello&quot; 中的 &quot;world!&quot;。</li></ul></li><li><p>正则表达式 <code>^Hello, world!$</code>：</p><ul><li>匹配：完全匹配 &quot;Hello, world!&quot; 的字符串。</li><li>示例：<code>^Hello, world!$</code> 只能匹配 &quot;Hello, world!&quot;，不匹配其他字符串。</li></ul></li><li><p>正则表达式 <code>^$</code>：</p><ul><li>匹配：空字符串。</li><li>示例：<code>^$</code> 只能匹配空字符串。</li></ul></li></ol><p>这些锚点非常有用，可以用于确保匹配发生在字符串的指定位置，从而实现更精确的匹配。</p><h2 id="中级阶段" tabindex="-1">中级阶段 <a class="header-anchor" href="#中级阶段" aria-label="Permalink to &quot;中级阶段&quot;">​</a></h2><h2 id="深入理解分组和捕获" tabindex="-1">深入理解分组和捕获 <a class="header-anchor" href="#深入理解分组和捕获" aria-label="Permalink to &quot;深入理解分组和捕获&quot;">​</a></h2><h3 id="学习如何使用小括号-进行分组" tabindex="-1">学习如何使用小括号<code>()</code>进行分组 <a class="header-anchor" href="#学习如何使用小括号-进行分组" aria-label="Permalink to &quot;学习如何使用小括号`()`进行分组&quot;">​</a></h3><p>小括号 <code>()</code> 在正则表达式中用于创建一个子表达式，也称为分组。分组可以将多个字符或子表达式组合成一个单元，从而可以对这个单元进行量词操作、引用等。</p><p>下面是使用小括号 <code>()</code> 进行分组的一些示例和说明：</p><ol><li><p><strong>分组示例</strong>：</p><ul><li>正则表达式 <code>(\\d{3})-\\d{3}-\\d{4}</code> 匹配电话号码，并将区号部分 <code>\\d{3}</code> 放在第一个分组中。</li></ul></li><li><p><strong>量词操作</strong>：</p><ul><li>可以对整个分组进行量词操作，例如 <code>(\\d{3}){2}</code> 表示匹配两次区号。</li><li>正则表达式 <code>(ab)+</code> 匹配一个或多个连续的 &quot;ab&quot;。</li></ul></li><li><p><strong>引用</strong>：</p><ul><li>可以通过反向引用来引用分组，例如 <code>\\1</code> 表示引用第一个分组。</li><li>正则表达式 <code>(\\w+)\\s\\1</code> 可以用来匹配重复的单词，例如 &quot;hello hello&quot;。</li></ul></li><li><p><strong>捕获组</strong>：</p><ul><li>分组还可以作为捕获组，匹配的内容可以在匹配后进行提取和使用。</li><li>在一些编程语言中，捕获组的匹配结果可以通过索引或命名进行访问。</li></ul></li></ol><p>分组可以使正则表达式更加灵活和强大，你可以根据实际需求合理地使用分组来构建更复杂的匹配规则。</p><h3 id="理解捕获组的概念和用法" tabindex="-1">理解捕获组的概念和用法 <a class="header-anchor" href="#理解捕获组的概念和用法" aria-label="Permalink to &quot;理解捕获组的概念和用法&quot;">​</a></h3><p>捕获组是正则表达式中的一种特性，它允许你将匹配到的子字符串单独提取出来，并在匹配后进行访问和使用。当你使用小括号 <code>()</code> 将一个部分包围起来时，这个部分就成为了一个捕获组。捕获组在很多编程语言和正则表达式引擎中都有广泛的支持。</p><ul><li><strong>捕获组的用法</strong>：</li></ul><ol><li><p><strong>提取匹配的内容：</strong> 捕获组允许你在匹配后从原始字符串中提取出你感兴趣的部分。这对于从文本中提取特定信息非常有用，比如从电话号码中提取区号。</p></li><li><p><strong>引用捕获组：</strong> 在正则表达式中，你可以使用反向引用来引用捕获组。这意味着你可以在同一正则表达式中引用之前匹配到的内容，从而实现更复杂的匹配规则。例如，你可以匹配重复的单词或重复的数字。</p></li><li><p><strong>在匹配后使用捕获组：</strong> 一旦正则表达式匹配成功，你可以使用编程语言的正则表达式相关函数来访问捕获组中的内容，并在程序中进一步处理或使用这些内容。不同的编程语言提供了不同的方式来访问捕获组中的内容，通常是通过索引或命名来访问。</p></li></ol><ul><li><strong>示例</strong>：</li></ul><p>假设我们有一个字符串 &quot;My email address is <a href="mailto:example@example.com" target="_blank" rel="noreferrer">example@example.com</a>&quot;，我们想要提取出其中的邮箱地址。</p><p>使用正则表达式 <code>/(\\w+@\\w+\\.\\w+)/</code>，其中 <code>(\\w+@\\w+\\.\\w+)</code> 是一个捕获组，可以匹配一个邮箱地址，并提取出来。</p><p>在编程中，你可以使用正则表达式引擎提供的相关函数，比如在 Python 中使用 <code>re.match()</code> 或 <code>re.search()</code>，来匹配字符串，并访问捕获组中的内容。</p><p>总之，捕获组是正则表达式中一种非常有用的特性，可以帮助你从文本中提取出你感兴趣的内容，并在程序中进一步处理和使用。</p><h3 id="学习如何引用捕获组" tabindex="-1">学习如何引用捕获组 <a class="header-anchor" href="#学习如何引用捕获组" aria-label="Permalink to &quot;学习如何引用捕获组&quot;">​</a></h3><p>在正则表达式中，引用捕获组是指在同一个正则表达式中使用已经匹配到的捕获组的内容。这种引用通常使用反向引用来实现。下面是一些关于如何引用捕获组的基本知识和示例：</p><ol><li>使用反向引用来引用捕获组：</li></ol><p>在正则表达式中，可以使用 <code>\\数字</code> 来引用之前定义的捕获组，其中数字表示捕获组的索引，从 1 开始计数。</p><p>例如，假设我们有一个正则表达式 <code>(\\w+)\\s\\1</code>，其中 <code>(\\w+)</code> 是第一个捕获组，匹配一个或多个单词字符，<code>\\s</code> 匹配一个空白字符，<code>\\1</code> 表示引用第一个捕获组。这个正则表达式将匹配重复的单词。</p><p><strong>示例</strong>：</p><p>考虑字符串 &quot;hello hello&quot;，我们想要匹配其中重复的单词。</p><ul><li>正则表达式：<code>(\\w+)\\s\\1</code><ul><li><code>(\\w+)</code>：第一个捕获组，匹配一个或多个单词字符。</li><li><code>\\s</code>：匹配一个空白字符。</li><li><code>\\1</code>：引用第一个捕获组。</li></ul></li><li>匹配结果：匹配到 &quot;hello hello&quot;，因为第一个 &quot;hello&quot; 被捕获到了，然后 <code>\\1</code> 引用了第一个捕获组，所以它要求匹配到的内容必须与第一个捕获组相同，于是第二个 &quot;hello&quot; 也被匹配到了。</li></ul><ol start="2"><li><strong>在代码中引用捕获组</strong>：</li></ol><p>在使用正则表达式进行匹配的编程语言中，通常提供了相应的函数来访问捕获组的内容。你可以使用这些函数来获取捕获组中的内容，并在程序中进一步处理。</p><p>以 Python 为例，可以使用 <code>re</code> 模块中的 <code>match()</code> 或 <code>search()</code> 函数来进行正则表达式匹配，并使用 <code>group()</code> 方法来访问捕获组中的内容。</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> re</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">text </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;hello hello&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pattern </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">(\\w</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">)\\s</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">\\1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">match </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> re.search(pattern, text)</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> match:</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    print</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Match found:&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, match.group(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 打印整个匹配到的内容</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    print</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Captured group:&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, match.group(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 打印第一个捕获组的内容</span></span></code></pre></div><p>总之，引用捕获组是一种在正则表达式中使用已经匹配到的内容的强大技术，可以帮助你构建更复杂和灵活的匹配规则。</p><h2 id="掌握常用的预定义字符类" tabindex="-1">掌握常用的预定义字符类 <a class="header-anchor" href="#掌握常用的预定义字符类" aria-label="Permalink to &quot;掌握常用的预定义字符类&quot;">​</a></h2><h3 id="学习如何使用-d、-w、-s等预定义字符类匹配数字、字母、空白字符等" tabindex="-1">学习如何使用<code>\\d</code>、<code>\\w</code>、<code>\\s</code>等预定义字符类匹配数字、字母、空白字符等 <a class="header-anchor" href="#学习如何使用-d、-w、-s等预定义字符类匹配数字、字母、空白字符等" aria-label="Permalink to &quot;学习如何使用`\\d`、`\\w`、`\\s`等预定义字符类匹配数字、字母、空白字符等&quot;">​</a></h3><p>在正则表达式中，<code>\\d</code>、<code>\\w</code>、<code>\\s</code> 等是预定义字符类，用于匹配特定类型的字符。它们的含义如下：</p><ul><li><code>\\d</code>：匹配任意一个数字字符，相当于字符类 <code>[0-9]</code>。</li><li><code>\\w</code>：匹配任意一个字母、数字或下划线字符（即单词字符），相当于字符类 <code>[A-Za-z0-9_]</code>。</li><li><code>\\s</code>：匹配任意一个空白字符，包括空格、制表符、换行符等。</li></ul><p>以下是一些示例，演示如何使用这些预定义字符类：</p><ol><li><p>匹配一个数字字符：</p><ul><li>正则表达式：<code>\\d</code></li><li>匹配：任意一个数字字符，包括 &quot;0&quot; 到 &quot;9&quot; 之间的任意一个数字。</li></ul></li><li><p>匹配一个字母、数字或下划线字符：</p><ul><li>正则表达式：<code>\\w</code></li><li>匹配：任意一个字母、数字或下划线字符，包括大写字母、小写字母、数字和下划线。</li></ul></li><li><p>匹配一个空白字符：</p><ul><li>正则表达式：<code>\\s</code></li><li>匹配：任意一个空白字符，包括空格、制表符、换行符等。</li></ul></li></ol><p>示例代码（使用 Python 的 re 模块）：</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> re</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">text </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;The number is 123, and the word is hello world.&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pattern_digit </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pattern_word </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\w</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pattern_space </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 匹配数字字符</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">matches_digit </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> re.findall(pattern_digit, text)</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">print</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Digits:&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, matches_digit)</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 匹配字母、数字或下划线字符</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">matches_word </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> re.findall(pattern_word, text)</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">print</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Words:&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, matches_word)</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 匹配空白字符</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">matches_space </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> re.findall(pattern_space, text)</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">print</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Spaces:&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, matches_space)</span></span></code></pre></div><p>输出结果会分别显示匹配到的数字字符、字母、数字或下划线字符以及空白字符。</p><h2 id="了解量词的贪婪与非贪婪" tabindex="-1">了解量词的贪婪与非贪婪 <a class="header-anchor" href="#了解量词的贪婪与非贪婪" aria-label="Permalink to &quot;了解量词的贪婪与非贪婪&quot;">​</a></h2><h3 id="深入理解量词-、-、-的贪婪匹配和非贪婪匹配" tabindex="-1">深入理解量词<code>*</code>、<code>+</code>、<code>?</code>的贪婪匹配和非贪婪匹配 <a class="header-anchor" href="#深入理解量词-、-、-的贪婪匹配和非贪婪匹配" aria-label="Permalink to &quot;深入理解量词`*`、`+`、`?`的贪婪匹配和非贪婪匹配&quot;">​</a></h3><p>理解量词 <code>*</code>、<code>+</code> 和 <code>?</code> 的贪婪匹配和非贪婪匹配是使用正则表达式时非常重要的概念。</p><ol><li><p><strong>贪婪匹配</strong>：</p><ul><li>默认情况下，<code>*</code>、<code>+</code> 和 <code>?</code> 都是贪婪的，它们会尽可能多地匹配目标文本，直到不能匹配为止。</li><li>在贪婪模式下，正则表达式引擎会尝试匹配尽可能长的字符串。</li><li>贪婪匹配的量词会尽可能多地匹配符合条件的文本，而且不会考虑后续可能的匹配情况。</li></ul></li><li><p><strong>非贪婪匹配（懒惰匹配）</strong>：</p><ul><li>在量词后面添加 <code>?</code> 可以将贪婪匹配转换为非贪婪匹配。</li><li>非贪婪匹配会尽可能少地匹配目标文本，直到满足匹配条件为止。</li><li>非贪婪匹配会尽可能少地匹配符合条件的文本，以便为后续的匹配留下更多的机会。</li></ul></li></ol><ul><li><strong>示例</strong>：</li></ul><p>考虑正则表达式 <code>.*</code>，它表示匹配任意数量（包括零个）的任意字符。</p><ul><li>在贪婪模式下，正则表达式引擎会尽可能多地匹配文本，因此会匹配尽可能长的字符串。</li><li>在非贪婪模式下，添加 <code>?</code> 后，正则表达式引擎会尽可能少地匹配文本，因此会匹配尽可能短的字符串。</li></ul><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>目标文本：abcdefg</span></span>\n<span class="line"><span>正则表达式：.*</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>贪婪匹配结果：abcdefg</span></span>\n<span class="line"><span>非贪婪匹配结果：a</span></span></code></pre></div><p>在贪婪模式下，<code>.*</code> 匹配了整个目标文本 &quot;abcdefg&quot;，而在非贪婪模式下，<code>.*?</code> 只匹配了目标文本的第一个字符 &quot;a&quot;。</p><p>总之，理解量词 <code>*</code>、<code>+</code> 和 <code>?</code> 的贪婪匹配和非贪婪匹配可以帮助你编写更加精确和有效的正则表达式，从而实现各种文本匹配和处理任务。</p><h2 id="学习反向引用" tabindex="-1">学习反向引用 <a class="header-anchor" href="#学习反向引用" aria-label="Permalink to &quot;学习反向引用&quot;">​</a></h2><h3 id="掌握如何使用-1、-2等反向引用捕获组" tabindex="-1">掌握如何使用<code>\\1</code>、<code>\\2</code>等反向引用捕获组 <a class="header-anchor" href="#掌握如何使用-1、-2等反向引用捕获组" aria-label="Permalink to &quot;掌握如何使用`\\1`、`\\2`等反向引用捕获组&quot;">​</a></h3><p>反向引用捕获组是指在正则表达式中引用已经匹配到的捕获组的内容。在大多数编程语言和正则表达式引擎中，你可以使用 <code>\\数字</code> 来引用捕获组，其中数字表示捕获组的索引，从 1 开始计数。</p><p>以下是一些关于如何使用反向引用捕获组的基本知识和示例：</p><ul><li><strong>使用反向引用</strong>：</li></ul><ol><li><p>在正则表达式中，使用 <code>\\数字</code> 来引用之前定义的捕获组。</p></li><li><p>数字表示捕获组的索引，从 1 开始计数，即第一个捕获组的索引是 1，第二个捕获组的索引是 2，依此类推。</p></li><li><p>在正则表达式中，可以在需要引用捕获组的地方使用 <code>\\数字</code>，例如替换字符串中、在匹配模式中等。</p></li></ol><ul><li><strong>示例</strong>：</li></ul><p>假设我们有一个字符串 &quot;hello hello&quot;，我们想要匹配其中重复的单词，并将重复的单词替换为单个单词。</p><ol><li>正则表达式：<code>(\\w+)\\s\\1</code><ul><li><code>(\\w+)</code>：第一个捕获组，匹配一个或多个单词字符。</li><li><code>\\s</code>：匹配一个空白字符。</li><li><code>\\1</code>：引用第一个捕获组。</li></ul></li><li>替换字符串：<code>\\1</code><ul><li>将匹配到的重复单词替换为第一个捕获组的内容。</li></ul></li></ol><p>在代码中，我们可以使用编程语言提供的正则表达式替换函数，如 Python 中的 <code>re.sub()</code>，来实现这个功能。</p><ul><li><strong>示例代码（Python）</strong>：</li></ul><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> re</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">text </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;hello hello&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pattern </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">(\\w</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">)\\s</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">\\1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">replacement </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">\\1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">result </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> re.sub(pattern, replacement, text)</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">print</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(result)  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 输出 &quot;hello&quot;</span></span></code></pre></div><p>在这个示例中，正则表达式 <code>(\\w+)\\s\\1</code> 匹配了重复的单词，并使用 <code>\\1</code> 将重复的单词替换为第一个捕获组的内容，最终输出结果为 &quot;hello&quot;。</p><p><strong>高级阶段</strong>和<strong>进阶阶段</strong>用不到</p>',132)]))}const k=l(t,[["render",e]]);export{r as __pageData,k as default};
